"use strict";parserFactory.registerUrlRule(e=>util.extractHostName(e).endsWith(".wikipedia.org"),()=>new WikipediaParser),parserFactory.registerManualSelect("Wikipedia",()=>new WikipediaParser);class WikipediaParser extends Parser{constructor(){super()}getChapterUrls(e){let t={sourceUrl:e.baseURI,title:e.title};return Promise.resolve([t])}findContent(e){return e.getElementById("bodyContent")}removeUnwantedElementsFromContentElement(e){super.removeUnwantedElementsFromContentElement(e),this.removeEditElements(e),this.removeExternalLinkTables(e),this.removeExternalHyperlinks(e)}removeEditElements(e){util.removeElements(e.querySelectorAll("span.mw-editsection"))}removeExternalLinkTables(e){util.removeElements(e.querySelectorAll("div.navbox"))}removeExternalHyperlinks(e){for(let t of util.getElements(e,"a",e=>!this.isLinkToKeep(e)))this.replaceHyperlinkWithTextContent(t)}isLinkToKeep(e){return!util.isNullOrEmpty(e.hash)||null!==e.querySelector("img, image")}replaceHyperlinkWithTextContent(e){let t=e.textContent;if(util.isNullOrEmpty(t))e.remove();else{let r=e.ownerDocument.createTextNode(t);e.replaceWith(r)}}}